#include <iostream>
using namespace std;
int t,a[10000005],s1[10000005];
int main()
{
    cin>>t;
    for(int i=0;i<=t-1;i++)
    {
        string s;
        cin>>s;
        for(int j=0;j<=s.size()-1;j++)
        {
            if(s[j]=='P')
            {
                a[j+1]=3;
            }
            else if(s[j]=='p')
            {
                a[j+1]=2;
            }
            else if(s[j]=='G')
            {
                a[j+1]=1;
            }
            else
            {
                a[j+1]=0;
            }
            for(int x=j+1;x<=s.size();x++)
            {
                s1[x]+=a[j+1];
            }
        }
        int q;
        cin>>q;
        for(int j=0;j<=q-1;j++)
        {
            int l,r;
            cin>>l>>r;
            cout<<s1[r]-s1[l-1]<<endl;
        }
        for(int j=0;j<=1004;j++)
        {
            s1[j]=0;
        }
    }
}
